## **5. TEXT AND JSON FORMATTING PATTERN**

### **Event Entry Type (src/daemon/commands.ts: line 40)**

```typescript
export type EventEntry = { text: string | undefined; json: string };
```

### **Formatting Functions Pattern (src/daemon/commands.ts: lines 623-686)**

All event types follow this pattern:

```typescript
export function onChatMessage(
  msg: ChatMessage,
  events: RingBuffer<EventEntry>,
  log: SessionLog,
): void {
  const obj = formatMessageObj(msg);
  events.push({ text: formatMessage(msg), json: JSON.stringify(obj) });
  log.append(obj).catch(() => {});
}

export function onGroupEvent(
  event: GroupEvent,
  events: RingBuffer<EventEntry>,
  log: SessionLog,
): void {
  const text = formatGroupEvent(event);
  const obj = formatGroupEventObj(event);
  events.push({ text, json: JSON.stringify(obj) });
  log.append(obj as LogEntry).catch(() => {});
}

export function onDuelEvent(
  event: DuelEvent,
  events: RingBuffer<EventEntry>,
  log: SessionLog,
): void {
  const text = formatDuelEvent(event);
  const obj = formatDuelEventObj(event);
  if (obj) {
    events.push({ text, json: JSON.stringify(obj) });
    log.append(obj as LogEntry).catch(() => {});
  }
}
```

**Three-part pattern:**
1. Format text for TUI display (may return `undefined` if not user-visible)
2. Format object for JSON/logging (may return `undefined` if not loggable)
3. Push both to ring buffer AND append to session log

