## **6. TUI FORMATTING (src/ui/format.ts)**

### **Text Formatters**

```typescript
export function formatMessage(msg: ChatMessage): string {
  const message = stripColorCodes(msg.message);
  const label = CHAT_TYPE_LABELS[msg.type] ?? `type ${msg.type}`;

  if (msg.type === ChatType.WHISPER) {
    return `[whisper from ${msg.sender}] ${message}`;
  }
  if (msg.type === ChatType.WHISPER_INFORM) {
    return `[whisper to ${msg.sender}] ${message}`;
  }
  if (
    msg.type === ChatType.SYSTEM &&
    (msg.origin === "server" || msg.origin === "notification")
  ) {
    return `[server] ${message}`;
  }
  if (msg.type === ChatType.SYSTEM && msg.origin === "mail") {
    return `[mail] ${message}`;
  }
  if (msg.type === ChatType.SYSTEM) {
    return `[system] ${message}`;
  }
  // ... etc
  return `[${label}] ${msg.sender}: ${message}`;
}

export function formatGroupEvent(event: GroupEvent): string | undefined {
  switch (event.type) {
    case "invite_received":
      return `[group] ${event.from} invites you to a group`;
    case "command_result": {
      // ... detailed formatting logic ...
      return `[group] ${label}`;
    }
    case "leader_changed":
      return `[group] ${event.name} is now the group leader`;
    // ... returns undefined for internal events like "group_list" ...
  }
}
```

### **JSON Formatters**

```typescript
export function formatMessageObj(msg: ChatMessage): LogEntry {
  const type =
    msg.origin === "server"
      ? "SERVER_BROADCAST"
      : msg.origin === "notification"
        ? "NOTIFICATION"
        : msg.origin === "mail"
          ? "MAIL"
          : (JSON_TYPE_LABELS[msg.type] ?? `TYPE_${msg.type}`);
  const obj: LogEntry = {
    type,
    sender: msg.sender,
    message: stripColorCodes(msg.message),
  };
  if (msg.channel) obj.channel = msg.channel;
  return obj;
}

function formatGroupEventObj(event: GroupEvent): Record<string, unknown> {
  switch (event.type) {
    case "invite_received":
      return { type: "GROUP_INVITE", from: event.from };
    case "command_result":
      return {
        type: "GROUP_COMMAND_RESULT",
        operation: event.operation,
        target: event.target,
        result: event.result,
      };
    case "leader_changed":
      return { type: "GROUP_LEADER_CHANGED", name: event.name };
    case "group_destroyed":
      return { type: "GROUP_DESTROYED" };
    case "kicked":
      return { type: "GROUP_KICKED" };
    case "invite_declined":
      return { type: "GROUP_INVITE_DECLINED", name: event.name };
    case "group_list":
      return {
        type: "GROUP_LIST",
        members: event.members.map((m) => ({
          name: m.name,
          online: m.online,
        })),
        leader: event.leader,
      };
    case "member_stats":
      return {
        type: "PARTY_MEMBER_STATS",
        guidLow: event.guidLow,
        online: event.online,
        hp: event.hp,
        maxHp: event.maxHp,
        level: event.level,
      };
  }
}
```

